import React, { useState, useEffect } from 'react';
import { 
  View, 
  Text, 
  StyleSheet, 
  Alert, 
  Image,
  ScrollView 
} from 'react-native';
import { 
  Card, 
  Title, 
  Paragraph, 
  Button, 
  ActivityIndicator,
  Chip 
} from 'react-native-paper';
import { MaterialCommunityIcons } from '@expo/vector-icons';
import * as ImagePicker from 'expo-image-picker';
import * as Camera from 'expo-camera';
import { theme, styles } from '../styles/theme';

const DiseaseDetectionScreen = () => {
  const [image, setImage] = useState(null);
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState(null);
  const [hasPermission, setHasPermission] = useState(null);

  useEffect(() => {
    (async () => {
      const cameraStatus = await Camera.requestCameraPermissionsAsync();
      const galleryStatus = await ImagePicker.requestMediaLibraryPermissionsAsync();
      setHasPermission(cameraStatus.status === 'granted' && galleryStatus.status === 'granted');
    })();
  }, []);

  const takePhoto = async () => {
    if (!hasPermission) {
      Alert.alert('अनुमति चाहिए', 'कृपया कैमरा की अनुमति दें');
      return;
    }

    const result = await ImagePicker.launchCameraAsync({
      mediaTypes: ImagePicker.MediaTypeOptions.Images,
      allowsEditing: true,
      aspect: [4, 3],
      quality: 0.8,
    });

    if (!result.canceled) {
      setImage(result.assets[0].uri);
      analyzeImage(result.assets[0].uri);
    }
  };

  const pickImage = async () => {
    const result = await ImagePicker.launchImageLibraryAsync({
      mediaTypes: ImagePicker.MediaTypeOptions.Images,
      allowsEditing: true,
      aspect: [4, 3],
      quality: 0.8,
    });

    if (!result.canceled) {
      setImage(result.assets[0].uri);
      analyzeImage(result.assets[0].uri);
    }
  };

  const analyzeImage = async (imageUri) => {
    setLoading(true);
    setResult(null);
    
    // Simulate API call to disease detection service
    setTimeout(() => {
      // Mock result for demonstration
      const mockResults = [
        {
          disease: 'पत्ती का धब्बा रोग',
          confidence: 92,
          severity: 'मध्यम',
          treatment: 'तांबा युक्त कवकनाशी का छिड़काव करें। प्रभावित पत्तियों को हटा दें।',
          prevention: 'खेत में जल निकासी का उचित प्रबंध करें। बीज उपचार जरूर करें।',
          organicTreatment: 'नीम का तेल मिलाकर छिड़काव करें। हल्दी और गुड़ का घोल भी प्रभावी है।'
        },
        {
          disease: 'स्वस्थ पत्ती',
          confidence: 89,
          severity: 'कोई समस्या नहीं',
          treatment: 'आपकी फसल स्वस्थ है। नियमित देखभाल जारी रखें।',
          prevention: 'संतुलित खाद और पानी देते रहें। समय पर निराई-गुड़ाई करें।',
          organicTreatment: 'जैविक खाद का उपयोग जारी रखें।'
        }
      ];
      
      const randomResult = mockResults[Math.floor(Math.random() * mockResults.length)];
      setResult(randomResult);
      setLoading(false);
    }, 2000);
  };

  const getSeverityColor = (severity) => {
    switch (severity.toLowerCase()) {
      case 'गंभीर':
        return theme.colors.error;
      case 'मध्यम':
        return theme.colors.warning;
      case 'हल्का':
        return theme.colors.info;
      default:
        return theme.colors.success;
    }
  };

  return (
    <ScrollView style={diseaseStyles.container}>
      <Card style={[styles.card]}>
        <Title style={diseaseStyles.title}>पौधे की बीमारी पहचानें</Title>
        <Paragraph style={diseaseStyles.subtitle}>
          पत्ती की फोटो खींचें या अपलोड करें
        </Paragraph>

        {!image && (
          <View style={diseaseStyles.buttonContainer}>
            <Button
              mode="contained"
              style={[styles.button, diseaseStyles.cameraButton]}
              onPress={takePhoto}
              contentStyle={styles.farmerfriendly}
            >
              <MaterialCommunityIcons name="camera" size={24} color="white" />
              {'  '}फोटो खींचें
            </Button>

            <Button
              mode="outlined"
              style={[styles.button, diseaseStyles.galleryButton]}
              onPress={pickImage}
              contentStyle={styles.farmerfriendly}
            >
              <MaterialCommunityIcons name="image" size={24} color={theme.colors.primary} />
              {'  '}गैलरी से चुनें
            </Button>
          </View>
        )}

        {image && (
          <View style={diseaseStyles.imageContainer}>
            <Image source={{ uri: image }} style={diseaseStyles.image} />
            <View style={diseaseStyles.imageActions}>
              <Button
                mode="outlined"
                onPress={() => {
                  setImage(null);
                  setResult(null);
                }}
                style={diseaseStyles.retakeButton}
              >
                दूसरी फोटो लें
              </Button>
            </View>
          </View>
        )}
      </Card>

      {loading && (
        <Card style={[styles.card]}>
          <View style={diseaseStyles.loadingContainer}>
            <ActivityIndicator size="large" color={theme.colors.primary} />
            <Text style={diseaseStyles.loadingText}>
              AI से जांच की जा रही है...
            </Text>
          </View>
        </Card>
      )}

      {result && !loading && (
        <Card style={[styles.card]}>
          <View style={diseaseStyles.resultHeader}>
            <Title style={diseaseStyles.resultTitle}>जांच का परिणाम</Title>
            <Chip 
              style={[diseaseStyles.confidenceChip, { backgroundColor: getSeverityColor(result.severity) }]}
              textStyle={{ color: 'white', fontWeight: 'bold' }}
            >
              {result.confidence}% सटीक
            </Chip>
          </View>

          <Card style={diseaseStyles.resultCard}>
            <View style={diseaseStyles.diseaseInfo}>
              <MaterialCommunityIcons 
                name="leaf" 
                size={32} 
                color={getSeverityColor(result.severity)} 
              />
              <View style={diseaseStyles.diseaseText}>
                <Text style={diseaseStyles.diseaseName}>{result.disease}</Text>
                <Text style={[diseaseStyles.severity, { color: getSeverityColor(result.severity) }]}>
                  गंभीरता: {result.severity}
                </Text>
              </View>
            </View>
          </Card>

          <Card style={diseaseStyles.treatmentCard}>
            <Title style={diseaseStyles.treatmentTitle}>
              <MaterialCommunityIcons name="medical-bag" size={20} />
              {'  '}उपचार
            </Title>
            <Paragraph style={diseaseStyles.treatmentText}>
              {result.treatment}
            </Paragraph>
          </Card>

          <Card style={diseaseStyles.treatmentCard}>
            <Title style={diseaseStyles.treatmentTitle}>
              <MaterialCommunityIcons name="leaf" size={20} />
              {'  '}जैविक उपचार
            </Title>
            <Paragraph style={diseaseStyles.treatmentText}>
              {result.organicTreatment}
            </Paragraph>
          </Card>

          <Card style={diseaseStyles.treatmentCard}>
            <Title style={diseaseStyles.treatmentTitle}>
              <MaterialCommunityIcons name="shield-check" size={20} />
              {'  '}भविष्य में बचाव
            </Title>
            <Paragraph style={diseaseStyles.treatmentText}>
              {result.prevention}
            </Paragraph>
          </Card>

          <Button
            mode="contained"
            style={[styles.button, { backgroundColor: theme.colors.success }]}
            onPress={() => {
              setImage(null);
              setResult(null);
            }}
          >
            नई जांच करें
          </Button>
        </Card>
      )}

      <Card style={[styles.card, { marginBottom: 20 }]}>
        <Title style={diseaseStyles.tipsTitle}>फोटो खींचने की सलाह</Title>
        <View style={diseaseStyles.tipItem}>
          <MaterialCommunityIcons name="lightbulb-on" size={16} color={theme.colors.warning} />
          <Text style={diseaseStyles.tipText}>अच्छी रोशनी में फोटो लें</Text>
        </View>
        <View style={diseaseStyles.tipItem}>
          <MaterialCommunityIcons name="lightbulb-on" size={16} color={theme.colors.warning} />
          <Text style={diseaseStyles.tipText}>पत्ती को पास से फोकस करें</Text>
        </View>
        <View style={diseaseStyles.tipItem}>
          <MaterialCommunityIcons name="lightbulb-on" size={16} color={theme.colors.warning} />
          <Text style={diseaseStyles.tipText}>साफ और स्पष्ट फोटो लें</Text>
        </View>
      </Card>
    </ScrollView>
  );
};

